function evaluate(input: { required: string[], flags: string[] }, state: { rewards: number[] }): boolean {
    // Check if all required flags are present in the state's flags
    for (const flag of input.required) {
        if (!state.flags.includes(flag)) {
            return false;
        }
    }

    // Check if any required flag is missing from the state's flags
    for (const flag of input.required) {
        if (!state.flags.includes(flag)) {
            return false;
        }
    }

    // Add input.reward to state.rewards if it is not already present
    for (const reward of input.reward) {
        if (!state.rewards.includes(reward)) {
            state.rewards.push(reward);
        }
    }

    return true;
}

