function evaluate(input: { options: { id: number, weight: number }[] }, state: { roll: number }): number {
    let maxWeight = 0;
    let resultId = -1;

    for (const option of input.options) {
        const currentWeight = option.weight;
        const cumulativeWeight = currentWeight + state.roll;

        if (cumulativeWeight > maxWeight) {
            maxWeight = cumulativeWeight;
            resultId = option.id;
        }
    }

    return resultId;
}

